mapper.select:
SELECT DISTINCT e.id, e.executor_name executorName, e.executor_address executorAddress, e.executor_group executorGroup, e.executor_app executorApp, e.metadata, e.version, e.heartbeat_time heartbeatTime, e.status, e.create_time createTime FROM executor_info e INNER JOIN executor_handler h ON e.executor_address = h.executor_address WHERE e.status = 1 AND h.handler_name = #{handlerName}
AND e.executor_group = #{executorGroup}
AND e.executor_app = #{executorApp}
ORDER BY e.executor_group ASC, e.executor_app ASC, e.executor_name ASC, e.executor_address ASC

SELECT e.executor_group executorGroup, e.executor_app executorApp, h.handler_name handlerName, MAX(h.handler_desc) handlerDesc, MAX(h.method_signature) methodSignature, MAX(h.update_time) updateTime, COUNT(DISTINCT e.executor_address) onlineExecutorCount FROM executor_info e INNER JOIN executor_handler h ON e.executor_address = h.executor_address WHERE e.status = 1
AND e.executor_group = #{executorGroup}
AND e.executor_app = #{executorApp}
GROUP BY e.executor_group, e.executor_app, h.handler_name ORDER BY e.executor_group ASC, e.executor_app ASC, h.handler_name ASC
